class SafeRenderer {
    public id: string
    protected fallback: string
    private _errors: int = 0
    static totalErrors: int = 0

    constructor(id: string, fallback: string) {
        this.id = id
        this.fallback = fallback
    }

    static getErrorCount(): int {
        return SafeRenderer.totalErrors
    }

    increment() {
        this._errors = this._errors + 1
        SafeRenderer.totalErrors = SafeRenderer.totalErrors + 1
    }

    render(data: int[], labels: string[]): string {
        try {
            if (data.length == 0) {
                throw new Error("empty data")
            }
            val score = data[0] * data[1] - data[2]
            if (score < 0) {
                throw new RangeError("negative score")
            }
            return <div
                id={this.id}
                data-score={score}
                data-errors={this._errors}
                data-global={SafeRenderer.getErrorCount()}
                data-valid={score > 0 && this._errors == 0 && !false}
            >
                <span data-val={score}>{labels[0]}: {score}</span>
                <small data-errors={this._errors}>
                    Errors: {this._errors} / {SafeRenderer.totalErrors}
                </small>
            </div>
        } catch (e: RangeError) {
            this.increment()
            return <div
                id={this.id}
                class="error range"
                data-errors={this._errors}
                data-global={SafeRenderer.getErrorCount()}
                data-flag={this._errors > 0 && SafeRenderer.totalErrors > 0}
            >
                <span class="msg">{this.fallback}</span>
                <small data-count={this._errors}>{this._errors} errors</small>
            </div>
        } catch (e: Error) {
            this.increment()
            return <div
                id={this.id}
                class="error"
                data-errors={this._errors}
                data-flag={this._errors > 0 && !false}
            >
                {this.fallback}
            </div>
        } catch {
            this.increment()
            return <div id={this.id} class="unknown">{this.fallback}</div>
        } finally {
            val logged = this._errors >= 0 && SafeRenderer.totalErrors >= 0
        }
    }
}

class SafeList extends SafeRenderer {
    public items: string[]
    public maxItems: int
    private _collapsed: bool = false
    static listErrors: int = 0

    constructor(id: string, fallback: string, items: string[], maxItems: int) {
        super(id, fallback)
        this.items = items
        this.maxItems = maxItems
        this._collapsed = items.length > maxItems
    }

    static getListErrors(): int {
        return SafeList.listErrors + SafeRenderer.getErrorCount()
    }

    renderItem(idx: int, data: int[]): string {
        try {
            if (idx >= this.items.length) {
                throw new RangeError("index out of bounds")
            }
            val score = data[idx] * this.maxItems - idx
            return <li
                data-idx={idx}
                data-score={score}
                data-valid={score > 0 && idx < this.items.length}
                data-flag={score > 0 && !this._collapsed && idx < this.maxItems}
            >
                {this.items[idx]}: {score}
            </li>
        } catch (e: RangeError) {
            SafeList.listErrors = SafeList.listErrors + 1
            return <li class="error" data-idx={idx} data-errors={SafeList.listErrors}>
                {this.fallback}
            </li>
        } catch {
            return <li class="unknown" data-idx={idx}>{this.fallback}</li>
        }
    }

    render(data: int[], labels: string[]): string {
        try {
            if (data.length == 0 || this.items.length == 0) {
                throw new Error("empty")
            }
            val item0 = this.renderItem(0, data)
            val itemN = this.renderItem(this.items.length - 1, data)
            val score = data[0] * this.maxItems - SafeList.listErrors
            return <ul
                id={this.id}
                data-count={this.items.length}
                data-max={this.maxItems}
                data-collapsed={this._collapsed}
                data-score={score}
                data-errors={this._errors}
                data-list-errors={SafeList.listErrors}
                data-global={SafeRenderer.getErrorCount()}
                data-flag={score > 0 && !this._collapsed && this._errors == 0 && SafeList.listErrors == 0}
            >
                {item0}
                {itemN}
                <li class="footer" data-total={SafeList.getListErrors()}>
                    Errors: {SafeList.getListErrors()}
                </li>
            </ul>
        } catch (e: Error) {
            this.increment()
            return <ul id={this.id} class="error" data-errors={this._errors}>
                <li>{this.fallback}</li>
            </ul>
        } finally {
            val done = SafeList.listErrors >= 0 && this._errors >= 0
        }
    }
}

